1	type Cell = [number, number]; // [x, y]
2	
3	const NEIGHBOR_OFFSETS: Cell[] = [
4	  [-1, -1], [0, -1], [1, -1],
5	  [-1, 0], [1, 0],
6	  [-1, 1], [0, 1], [1, 1],
7	];
8	
9	const key = (x: number, y: number): string => `${x},${y}`;
10	
11	const neighborsOf = (x: number, y: number): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	export function nextGeneration(cells: Cell[]): Cell[] {
15	  const liveKeys = new Set(cells.map(([x, y]) => key(x, y)));
16	  const isAlive = (x: number, y: number): boolean => liveKeys.has(key(x, y));
17	
18	  const countLiveNeighbors = (x: number, y: number): number =>
19	    neighborsOf(x, y).filter(([nx, ny]) => isAlive(nx, ny)).length;
20	
21	  const survivors = cells.filter(([x, y]) => {
22	    const liveNeighbors = countLiveNeighbors(x, y);
23	    return liveNeighbors === 2 || liveNeighbors === 3;
24	  });
25	
26	  const births = new Map<string, Cell>();
27	  for (const [x, y] of cells) {
28	    for (const [nx, ny] of neighborsOf(x, y)) {
29	      if (isAlive(nx, ny)) continue;
30	      if (countLiveNeighbors(nx, ny) === 3) births.set(key(nx, ny), [nx, ny]);
31	    }
32	  }
33	
34	  return [...survivors, ...births.values()];
35	}
