1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  // Simplest cases
6	  it("returns empty array for empty input", () => {
7	    expect(nextGeneration([])).toEqual([]);
8	  });
9	  it("single cell dies — [(0,0)] → []", () => {
10	    expect(nextGeneration([[0, 0]])).toEqual([]);
11	  });
12	
13	  // Rule 1 – Underpopulation (live cell with < 2 neighbors dies)
14	  it("two adjacent cells each have 1 neighbor and die — [(0,1),(1,1)] → []", () => {
15	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
16	  });
17	
18	  // Rule 2 – Survival (live cell with 2 or 3 neighbors lives on)
19	  it("live cell with 3 neighbors survives — (1,1) stays alive", () => {
20	    // (1,1) is alive with live neighbors (0,0),(2,0),(0,2) → 3 neighbors → survives
21	    const next = nextGeneration([[1, 1], [0, 0], [2, 0], [0, 2]]);
22	    expect(next).toContainEqual([1, 1]);
23	  });
24	
25	  // Rule 3 – Overpopulation (live cell with > 3 neighbors dies)
26	  it("live cell with 4 neighbors dies (overpopulation) — (1,1) removed", () => {
27	    // (1,1) alive with live neighbors (0,0),(2,0),(0,2),(2,2) → 4 neighbors → dies
28	    const next = nextGeneration([[1, 1], [0, 0], [2, 0], [0, 2], [2, 2]]);
29	    expect(next).not.toContainEqual([1, 1]);
30	  });
31	
32	  // Rule 4 – Reproduction (dead cell with exactly 3 neighbors becomes alive)
33	  it("dead cell with exactly 3 neighbors becomes alive — (1,1) born", () => {
34	    // L-shape: (0,0),(1,0),(0,1). Dead cell (1,1) has 3 live neighbors → born
35	    const next = nextGeneration([[0, 0], [1, 0], [0, 1]]);
36	    expect(next).toContainEqual([1, 1]);
37	  });
38	
39	  // Pattern examples
40	  it("blinker oscillates — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]", () => {
41	    const sortCells = (cells: [number, number][]) =>
42	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
43	    const next = nextGeneration([[0, 0], [0, 1], [0, 2]]);
44	    expect(sortCells(next)).toEqual(sortCells([[-1, 1], [0, 1], [1, 1]]));
45	  });
46	  it("block is a still life — unchanged", () => {
47	    const sortCells = (cells: [number, number][]) =>
48	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
49	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
50	    expect(sortCells(nextGeneration(block))).toEqual(sortCells(block));
51	  });
52	
53	  // Negative coordinates
54	  it("handles negative coordinates — blinker in negative space", () => {
55	    const sortCells = (cells: [number, number][]) =>
56	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
57	    const next = nextGeneration([[-1, -1], [-1, 0], [-1, 1]]);
58	    expect(sortCells(next)).toEqual(sortCells([[-2, 0], [-1, 0], [0, 0]]));
59	  });
60	});
